#include <bits/stdc++.h>
using namespace std;
int d[4][2]={{1,0},{-1,0},{0,-1},{0,1}};
int n,m,a,b,dist[502][502];
void bfs(int sx,int sy){
    queue<int> qx,qy;
    qx.push(sx),qy.push(sy),dist[sx][sy]=0;
    while(!qx.empty()){
        int fx=qx.front(),fy=qy.front();
        qx.pop(),qy.pop();
        for(int i=0;i<4;i++){
            int xx=fx+d[i][0],yy=fy+d[i][1];
            if(xx>0 && yy>0 && xx<=n && yy<=m && dist[xx][yy]>dist[fx][fy]+1)
            	dist[xx][yy]=dist[fx][fy]+1,qx.push(xx),qy.push(yy);
        }
    }
}
int main(){
    memset(dist,127,sizeof(dist));
    scanf("%d%d%d%d",&n,&m,&a,&b);
    for(int i=1;i<=a;i++){
        int x,y;
        scanf("%d%d",&x,&y);
        bfs(x,y);
    }
    for(int i=1;i<=b;i++){
        int x,y;
        scanf("%d%d",&x,&y);
        printf("%d\n",dist[x][y]);
    }
    return 0;
}
